 52→
 53→    override fun beforeVisitChildNodes(
 54→        node: ASTNode,
 55→        autoCorrect: Boolean,
 56→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 57→    ) {
 58→        if (node.elementType != THEN && node.elementType != ELSE) {
 59→            return
 60→        }
 61→
 62→        val firstChildNode = node.firstChildNode
 63→            ?: return
 64→
 65→        // Ignore when already wrapped in a block
 66→        if (firstChildNode.elementType == BLOCK) {
 67→            return
 68→        }
 69→
 70→        if (node.elementType == ELSE &&
 71→            firstChildNode.elementType == BINARY_EXPRESSION &&
 72→            firstChildNode.firstChildNode?.elementType == IF
 73→        ) {
 74→            // Allow
 75→            // val foo2 = if (bar1) {
 76→            //     "bar1"
 77→            // } else if (bar2) {
 78→            //     null
 79→            // } else {
 80→            //     null
 81→            // } ?: "something-else"
 82→            return
 83→        }
 84→
 85→        if (node.elementType == ELSE &&
 86→            firstChildNode.elementType == DOT_QUALIFIED_EXPRESSION &&
 87→            firstChildNode.firstChildNode?.elementType == IF
 88→        ) {
 89→            // Allow
 90→            // val foo = if (bar1) {
 91→            //     "bar1"
 92→            // } else if (bar2) {
 93→            //     "bar2"
 94→            // } else {
 95→            //     "bar3"
 96→            // }.plus("foo")
 97→            return
 98→        }
 99→
100→        if (!node.treePrev.textContains('\n')) {
101→            if (firstChildNode.elementType == IF) {
102→                // Allow single line for:
103→                // else if (...)
104→                return
105→            }
106→            if (!node.treeParent.textContains('\n')) {
107→                // Allow single line if statements as long as they are really simple (e.g. do not contain newlines)
108→                //    if (...) <statement> // no else statement
109→                //    if (...) <statement> else <statement>
110→                return
111→            }
112→
113→            Unit
114→        }
115→
116→        emit(firstChildNode.startOffset, "Missing { ... }", true)
117→        if (autoCorrect) {
118→            autocorrect(node)
119→        }
120→    }
